from flask import Flask, jsonify
from flask_cors import CORS

app = Flask(__name__)
CORS(app) # Tüm domain'lerden gelen isteklere izin verir

@app.route('/')
def hello_world():
    return jsonify({"message": "Merhaba, CORS etkinleştirildi!"})

@app.route('/api/data')
def get_data():
    return jsonify({"data": "Bu bir API verisidir.", "source": "Flask CORS"})

if __name__ == '__main__':
    app.run(debug=True)
